// === lang/kotlin.js

/*
Language: Kotlin
Description: Kotlin is an OSS statically typed programming language that targets the JVM, Android, JavaScript and Native.
Author: Sergey Mashkov <cy6erGn0m@gmail.com>
Website: https://kotlinlang.org
Category: common
*/

// syntax/lang/kotlin.js
// HighlightJs: v.9.16.2

hljs.registerLanguage('kotlin',
function(hljs) {
	var KEYWORDS = {
		keyword:
			'abstract as val var vararg get set class object open private protected public noinline ' +
			'crossinline dynamic final enum if else do while for when throw try catch finally ' +
			'import package is in fun override companion reified inline lateinit init ' +
			'interface annotation data sealed internal infix operator out by constructor super ' +
			'tailrec where const inner suspend typealias external expect actual ' +
			// to be deleted soon
			'trait volatile transient native default',
		built_in:
			'Byte Short Char Int Long Boolean Float Double Void Unit Nothing',
		literal:
			'true false null'
	};
	var KEYWORDS_WITH_LABEL = {
		className: 'keyword',
		begin: /\b(break|continue|return|this)\b/,
		starts: {
			contains: [
				{
					className: 'symbol',
					begin: /@\w+/
				}
			]
		}
	};
	var LABEL = {
		className: 'symbol', begin: hljs.UNDERSCORE_IDENT_RE + '@'
	};

	// for string templates
	var SUBST = {
		className: 'subst',
		begin: '\\${', end: '}', contains: [hljs.C_NUMBER_MODE]
	};
	var VARIABLE = {
		className: 'variable', begin: '\\$' + hljs.UNDERSCORE_IDENT_RE
	};
	var STRING = {
		className: 'string',
		variants: [
			{
				begin: '"""', end: '"""',
				contains: [VARIABLE, SUBST]
			},
			// Can't use built-in modes easily, as we want to use STRING in the meta
			// context as 'meta-string' and there's no syntax to remove explicitly set
			// classNames in built-in modes.
			{
				begin: '\'', end: '\'',
				illegal: /\n/,
				contains: [hljs.BACKSLASH_ESCAPE]
			},
			{
				begin: '"', end: '"',
				illegal: /\n/,
				contains: [hljs.BACKSLASH_ESCAPE, VARIABLE, SUBST]
			}
		]
	};
	SUBST.contains.push(STRING)

	var ANNOTATION_USE_SITE = {
		className: 'meta', begin: '@(?:file|property|field|get|set|receiver|param|setparam|delegate)\\s*:(?:\\s*' + hljs.UNDERSCORE_IDENT_RE + ')?'
	};
	var ANNOTATION = {
		className: 'meta', begin: '@' + hljs.UNDERSCORE_IDENT_RE,
		contains: [
			{
				begin: /\(/, end: /\)/,
				contains: [
					hljs.inherit(STRING, {className: 'meta-string'})
				]
			}
		]
	};

	// https://kotlinlang.org/docs/reference/whatsnew11.html#underscores-in-numeric-literals
	// According to the doc above, the number mode of kotlin is the same as java 8,
	// so the code below is copied from java.js
	var KOTLIN_NUMBER_RE = '\\b' +
		'(' +
			'0[bB]([01]+[01_]+[01]+|[01]+)' + // 0b...
			'|' +
			'0[xX]([a-fA-F0-9]+[a-fA-F0-9_]+[a-fA-F0-9]+|[a-fA-F0-9]+)' + // 0x...
			'|' +
			'(' +
				'([\\d]+[\\d_]+[\\d]+|[\\d]+)(\\.([\\d]+[\\d_]+[\\d]+|[\\d]+))?' +
				'|' +
				'\\.([\\d]+[\\d_]+[\\d]+|[\\d]+)' +
			')' +
			'([eE][-+]?\\d+)?' + // octal, decimal, float
		')' +
		'[lLfF]?';
	var KOTLIN_NUMBER_MODE = {
		className: 'number',
		begin: KOTLIN_NUMBER_RE,
		relevance: 0
	};
	var KOTLIN_NESTED_COMMENT = hljs.COMMENT(
		'/\\*', '\\*/',
		{ contains: [ hljs.C_BLOCK_COMMENT_MODE ] }
	);
	var KOTLIN_PAREN_TYPE = {
		variants: [
		{ className: 'type',
			begin: hljs.UNDERSCORE_IDENT_RE
		},
		{ begin: /\(/, end: /\)/,
			contains: [] //defined later
		}
	]
	};
	var KOTLIN_PAREN_TYPE2 = KOTLIN_PAREN_TYPE;
	KOTLIN_PAREN_TYPE2.variants[1].contains = [ KOTLIN_PAREN_TYPE ];
	KOTLIN_PAREN_TYPE.variants[1].contains = [ KOTLIN_PAREN_TYPE2 ];

	return {
		aliases: ['kt'],
		keywords: KEYWORDS,
		contains : [
			hljs.COMMENT(
				'/\\*\\*',
				'\\*/',
				{
					relevance : 0,
					contains : [{
						className : 'doctag',
						begin : '@[A-Za-z]+'
					}]
				}
			),
			hljs.C_LINE_COMMENT_MODE,
			KOTLIN_NESTED_COMMENT,
			KEYWORDS_WITH_LABEL,
			LABEL,
			ANNOTATION_USE_SITE,
			ANNOTATION,
			{
				className: 'function',
				beginKeywords: 'fun', end: '[(]|$',
				returnBegin: true,
				excludeEnd: true,
				keywords: KEYWORDS,
				illegal: /fun\s+(<.*>)?[^\s\(]+(\s+[^\s\(]+)\s*=/,
				relevance: 5,
				contains: [
					{
						begin: hljs.UNDERSCORE_IDENT_RE + '\\s*\\(', returnBegin: true,
						relevance: 0,
						contains: [hljs.UNDERSCORE_TITLE_MODE]
					},
					{
						className: 'type',
						begin: /</, end: />/, keywords: 'reified',
						relevance: 0
					},
					{
						className: 'params',
						begin: /\(/, end: /\)/,
						endsParent: true,
						keywords: KEYWORDS,
						relevance: 0,
						contains: [
							{
								begin: /:/, end: /[=,\/]/, endsWithParent: true,
								contains: [
									KOTLIN_PAREN_TYPE,
									hljs.C_LINE_COMMENT_MODE,
									KOTLIN_NESTED_COMMENT
								],
								relevance: 0
							},
							hljs.C_LINE_COMMENT_MODE,
							KOTLIN_NESTED_COMMENT,
							ANNOTATION_USE_SITE,
							ANNOTATION,
							STRING,
							hljs.C_NUMBER_MODE
						]
					},
					KOTLIN_NESTED_COMMENT
				]
			},
			{
				className: 'class',
				beginKeywords: 'class interface trait', end: /[:\{(]|$/, // remove 'trait' when removed from KEYWORDS
				excludeEnd: true,
				illegal: 'extends implements',
				contains: [
					{beginKeywords: 'public protected internal private constructor'},
					hljs.UNDERSCORE_TITLE_MODE,
					{
						className: 'type',
						begin: /</, end: />/, excludeBegin: true, excludeEnd: true,
						relevance: 0
					},
					{
						className: 'type',
						begin: /[,:]\s*/, end: /[<\(,]|$/, excludeBegin: true, returnEnd: true
					},
					ANNOTATION_USE_SITE,
					ANNOTATION
				]
			},
			STRING,
			{
				className: 'meta',
				begin: "^#!/usr/bin/env", end: '$',
				illegal: '\n'
			},
			KOTLIN_NUMBER_MODE
		]
	};
}
);

// #END

// === lang/objectivec.js

/*
Language: Objective-C
Author: Valerii Hiora <valerii.hiora@gmail.com>
Contributors: Angel G. Olloqui <angelgarcia.mail@gmail.com>, Matt Diephouse <matt@diephouse.com>, Andrew Farmer <ahfarmer@gmail.com>, Minh Nguyễn <mxn@1ec5.org>
Category: common
*/

// syntax/lang/objectivec.js
// HighlightJs: v.9.13.1

hljs.registerLanguage('objectivec',
function(hljs) {
	var API_CLASS = {
		className: 'built_in',
		begin: '\\b(AV|CA|CF|CG|CI|CL|CM|CN|CT|MK|MP|MTK|MTL|NS|SCN|SK|UI|WK|XC)\\w+',
	};
	var OBJC_KEYWORDS = {
		keyword:
			'int float while char export sizeof typedef const struct for union ' +
			'unsigned long volatile static bool mutable if do return goto void ' +
			'enum else break extern asm case short default double register explicit ' +
			'signed typename this switch continue wchar_t inline readonly assign ' +
			'readwrite self @synchronized id typeof ' +
			'nonatomic super unichar IBOutlet IBAction strong weak copy ' +
			'in out inout bycopy byref oneway __strong __weak __block __autoreleasing ' +
			'@private @protected @public @try @property @end @throw @catch @finally ' +
			'@autoreleasepool @synthesize @dynamic @selector @optional @required ' +
			'@encode @package @import @defs @compatibility_alias ' +
			'__bridge __bridge_transfer __bridge_retained __bridge_retain ' +
			'__covariant __contravariant __kindof ' +
			'_Nonnull _Nullable _Null_unspecified ' +
			'__FUNCTION__ __PRETTY_FUNCTION__ __attribute__ ' +
			'getter setter retain unsafe_unretained ' +
			'nonnull nullable null_unspecified null_resettable class instancetype ' +
			'NS_DESIGNATED_INITIALIZER NS_UNAVAILABLE NS_REQUIRES_SUPER ' +
			'NS_RETURNS_INNER_POINTER NS_INLINE NS_AVAILABLE NS_DEPRECATED ' +
			'NS_ENUM NS_OPTIONS NS_SWIFT_UNAVAILABLE ' +
			'NS_ASSUME_NONNULL_BEGIN NS_ASSUME_NONNULL_END ' +
			'NS_REFINED_FOR_SWIFT NS_SWIFT_NAME NS_SWIFT_NOTHROW ' +
			'NS_DURING NS_HANDLER NS_ENDHANDLER NS_VALUERETURN NS_VOIDRETURN',
		literal:
			'false true FALSE TRUE nil YES NO NULL',
		built_in:
			'BOOL dispatch_once_t dispatch_queue_t dispatch_sync dispatch_async dispatch_once'
	};
	var LEXEMES = /[a-zA-Z@][a-zA-Z0-9_]*/;
	var CLASS_KEYWORDS = '@interface @class @protocol @implementation';
	return {
		aliases: ['mm', 'objc', 'obj-c'],
		keywords: OBJC_KEYWORDS,
		lexemes: LEXEMES,
		illegal: '</',
		contains: [
			API_CLASS,
			hljs.C_LINE_COMMENT_MODE,
			hljs.C_BLOCK_COMMENT_MODE,
			hljs.C_NUMBER_MODE,
			hljs.QUOTE_STRING_MODE,
			{
				className: 'string',
				variants: [
					{
						begin: '@"', end: '"',
						illegal: '\\n',
						contains: [hljs.BACKSLASH_ESCAPE]
					},
					{
						begin: '\'', end: '[^\\\\]\'',
						illegal: '[^\\\\][^\']'
					}
				]
			},
			{
				className: 'meta',
				begin: '#',
				end: '$',
				contains: [
					{
						className: 'meta-string',
						variants: [
							{ begin: '\"', end: '\"' },
							{ begin: '<', end: '>' }
						]
					}
				]
			},
			{
				className: 'class',
				begin: '(' + CLASS_KEYWORDS.split(' ').join('|') + ')\\b', end: '({|$)', excludeEnd: true,
				keywords: CLASS_KEYWORDS, lexemes: LEXEMES,
				contains: [
					hljs.UNDERSCORE_TITLE_MODE
				]
			},
			{
				begin: '\\.'+hljs.UNDERSCORE_IDENT_RE,
				relevance: 0
			}
		]
	};
}
);

