// === lang/r.js

/*
Language: R
Author: Joe Cheng <joe@rstudio.org>
Category: scientific
*/

// syntax/lang/r.js
// HighlightJs: v.9.13.1

hljs.registerLanguage('r',
function(hljs) {
	var IDENT_RE = '([a-zA-Z]|\\.[a-zA-Z.])[a-zA-Z0-9._]*';

	return {
		contains: [
			hljs.HASH_COMMENT_MODE,
			{
				begin: IDENT_RE,
				lexemes: IDENT_RE,
				keywords: {
					keyword:
						'function if in break next repeat else for return switch while try tryCatch ' +
						'stop warning require library attach detach source setMethod setGeneric ' +
						'setGroupGeneric setClass ...',
					literal:
						'NULL NA TRUE FALSE T F Inf NaN NA_integer_|10 NA_real_|10 NA_character_|10 ' +
						'NA_complex_|10'
				},
				relevance: 0
			},
			{
				// hex value
				className: 'number',
				begin: "0[xX][0-9a-fA-F]+[Li]?\\b",
				relevance: 0
			},
			{
				// explicit integer
				className: 'number',
				begin: "\\d+(?:[eE][+\\-]?\\d*)?L\\b",
				relevance: 0
			},
			{
				// number with trailing decimal
				className: 'number',
				begin: "\\d+\\.(?!\\d)(?:i\\b)?",
				relevance: 0
			},
			{
				// number
				className: 'number',
				begin: "\\d+(?:\\.\\d*)?(?:[eE][+\\-]?\\d*)?i?\\b",
				relevance: 0
			},
			{
				// number with leading decimal
				className: 'number',
				begin: "\\.\\d+(?:[eE][+\\-]?\\d*)?i?\\b",
				relevance: 0
			},

			{
				// escaped identifier
				begin: '`',
				end: '`',
				relevance: 0
			},

			{
				className: 'string',
				contains: [hljs.BACKSLASH_ESCAPE],
				variants: [
					{begin: '"', end: '"'},
					{begin: "'", end: "'"}
				]
			}
		]
	};
}
);

// #END

// === lang/scala.js

/*
Language: Scala
Category: functional
Author: Jan Berkel <jan.berkel@gmail.com>
Contributors: Erik Osheim <d_m@plastic-idolatry.com>
*/

// syntax/lang/scala.js
// HighlightJs: v.9.13.1

hljs.registerLanguage('scala',
function(hljs) {

	var ANNOTATION = { className: 'meta', begin: '@[A-Za-z]+' };

	// used in strings for escaping/interpolation/substitution
	var SUBST = {
		className: 'subst',
		variants: [
			{begin: '\\$[A-Za-z0-9_]+'},
			{begin: '\\${', end: '}'}
		]
	};

	var STRING = {
		className: 'string',
		variants: [
			{
				begin: '"', end: '"',
				illegal: '\\n',
				contains: [hljs.BACKSLASH_ESCAPE]
			},
			{
				begin: '"""', end: '"""',
				relevance: 10
			},
			{
				begin: '[a-z]+"', end: '"',
				illegal: '\\n',
				contains: [hljs.BACKSLASH_ESCAPE, SUBST]
			},
			{
				className: 'string',
				begin: '[a-z]+"""', end: '"""',
				contains: [SUBST],
				relevance: 10
			}
		]

	};

	var SYMBOL = {
		className: 'symbol',
		begin: '\'\\w[\\w\\d_]*(?!\')'
	};

	var TYPE = {
		className: 'type',
		begin: '\\b[A-Z][A-Za-z0-9_]*',
		relevance: 0
	};

	var NAME = {
		className: 'title',
		begin: /[^0-9\n\t "'(),.`{}\[\]:;][^\n\t "'(),.`{}\[\]:;]+|[^0-9\n\t "'(),.`{}\[\]:;=]/,
		relevance: 0
	};

	var CLASS = {
		className: 'class',
		beginKeywords: 'class object trait type',
		end: /[:={\[\n;]/,
		excludeEnd: true,
		contains: [
			{
				beginKeywords: 'extends with',
				relevance: 10
			},
			{
				begin: /\[/,
				end: /\]/,
				excludeBegin: true,
				excludeEnd: true,
				relevance: 0,
				contains: [TYPE]
			},
			{
				className: 'params',
				begin: /\(/,
				end: /\)/,
				excludeBegin: true,
				excludeEnd: true,
				relevance: 0,
				contains: [TYPE]
			},
			NAME
		]
	};

	var METHOD = {
		className: 'function',
		beginKeywords: 'def',
		end: /[:={\[(\n;]/,
		excludeEnd: true,
		contains: [NAME]
	};

	return {
		keywords: {
			literal: 'true false null',
			keyword: 'type yield lazy override def with val var sealed abstract private trait object if forSome for while throw finally protected extends import final return else break new catch super class case package default try this match continue throws implicit'
		},
		contains: [
			hljs.C_LINE_COMMENT_MODE,
			hljs.C_BLOCK_COMMENT_MODE,
			STRING,
			SYMBOL,
			TYPE,
			METHOD,
			CLASS,
			hljs.C_NUMBER_MODE,
			ANNOTATION
		]
	};
}
);

